(function(w){"use strict";const ID="lcm";function parseIntExact(v){const s=String(v??"").replace(/,/g,"").trim();if(!/^[+-]?\d+$/.test(s))return null;try{return BigInt(s)}catch(_){return null}}function abs(n){return n<0n?-n:n}function gcd(a,b){a=abs(a);b=abs(b);while(b){const t=a%b;a=b;b=t}return a}function compute(x){const a=parseIntExact(x.a),b=parseIntExact(x.b);if(a===null||b===null)return{error:"정수를 올바르게 입력해 주세요."};if(a===0n||b===0n)return{value:"0"};return{value:abs((a/gcd(a,b))*b).toString()}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label for="hm-lcm-a">첫 번째 정수</label><input id="hm-lcm-a" class="hm-calc-input" inputmode="numeric" placeholder="예: 12"></div><div class="hm-calc-field"><label for="hm-lcm-b">두 번째 정수</label><input id="hm-lcm-b" class="hm-calc-input" inputmode="numeric" placeholder="예: 18"></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">최소공배수 계산</button><button type="button" class="hm-calc-btn secondary">초기화</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const [a,b]=root.querySelectorAll("input"),[go,reset]=root.querySelectorAll("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({a:a.value,b:b.value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("최소공배수",r.value));});reset.addEventListener("click",()=>{a.value=b.value="";api.setMessage(msg,"");api.clearResult(res);a.focus();});}w.HM_CALC.register(ID,{compute,render});})(window);
